<template>
  <div class="exam-session-page">
    <section v-if="loading" class="state-card">正在加载考试信息...</section>

    <section v-else-if="!examSession" class="state-card">
      <p>考试会话已失效，请返回考试中心重新开考。</p>
      <router-link class="ghost-link" to="/exercise/exam">返回考试中心</router-link>
    </section>

    <template v-else>
      <section class="summary-card">
        <div>
          <p class="eyebrow">Exam Session</p>
          <h1>{{ examSession.paperName }}</h1>
          <p class="description">
            {{ examSession.subjectName || '-' }} · {{ questions.length }} 题 · 总分
            {{ examSession.totalScore || 0 }} 分
          </p>
        </div>

        <div class="meta-grid">
          <div>
            <span>开始时间</span>
            <strong>{{ formatDateTime(examSession.startTime) }}</strong>
          </div>
          <div>
            <span>考试时长</span>
            <strong>{{ examDurationMinutes }} 分钟</strong>
          </div>
          <div>
            <span>剩余时间</span>
            <strong :class="timeClass">{{ displayRemainingTime }}</strong>
          </div>
          <div>
            <span>当前进度</span>
            <strong>{{ currentIndex + 1 }} / {{ questions.length }}</strong>
          </div>
        </div>
      </section>

      <section v-if="submittedResult" class="result-card">
        <div class="result-head">
          <h2>已完成交卷</h2>
          <span class="status-chip done">成绩已生成</span>
        </div>
        <div class="result-grid">
          <div>
            <span>总题数</span>
            <strong>{{ submittedResult.totalQuestions || 0 }} 题</strong>
          </div>
          <div>
            <span>答对题数</span>
            <strong>{{ submittedResult.correctQuestions || 0 }} 题</strong>
          </div>
          <div>
            <span>考试得分</span>
            <strong>{{ formatScore(submittedResult.score) }} 分</strong>
          </div>
          <div>
            <span>用时</span>
            <strong>{{ submittedResult.duration || 0 }} 分钟</strong>
          </div>
        </div>
        <div class="result-actions">
          <router-link class="ghost-link" :to="`/exercise/exam/records/${recordId}`">查看试卷详情</router-link>
          <router-link class="ghost-link" to="/exercise/exam/records">返回考试记录</router-link>
          <router-link class="ghost-link" to="/exercise/exam">继续考试</router-link>
        </div>
      </section>

      <template v-else>
        <section class="nav-card">
          <div class="card-head">
            <h2>答题卡</h2>
            <span>已作答 {{ answeredCount }} / {{ questions.length }}</span>
          </div>
          <div class="nav-grid">
            <button
              v-for="(question, index) in questions"
              :key="question.questionId"
              type="button"
              :class="[
                'nav-chip',
                index === currentIndex ? 'active' : '',
                isAnswered(question.questionId) ? 'answered' : ''
              ]"
              @click="goToQuestion(index)"
            >
              {{ index + 1 }}
            </button>
          </div>
        </section>

        <section v-if="currentQuestion" class="question-card">
          <div class="card-head">
            <h2>第 {{ currentIndex + 1 }} 题</h2>
            <div class="meta-pills">
              <span class="pill">{{ resolveTypeLabel(currentQuestion.type) }}</span>
              <span class="pill">{{ resolveDifficultyLabel(currentQuestion.difficulty) }}</span>
              <span class="pill">分值 {{ currentQuestion.score || 0 }}</span>
            </div>
          </div>

          <h3>{{ currentQuestion.title }}</h3>
          <p v-if="currentQuestion.content" class="content">{{ currentQuestion.content }}</p>
          <QuestionImageList
            v-model="currentImageAnnotationDrafts"
            :image-urls="currentQuestion.imageUrls"
            :image-desc="currentQuestion.imageDesc"
            :annotation-object-names="currentImageAnnotationObjectNames"
            @dirty="saveClientState"
          />

          <div v-if="isChoiceQuestion(currentQuestion.type)" class="option-list">
            <button
              v-for="option in currentOptions"
              :key="option.optionKey"
              type="button"
              :class="[
                'option-item',
                isOptionActive(currentQuestion, option) ? 'active' : ''
              ]"
              @click="toggleOption(currentQuestion, option)"
            >
              <span class="option-key">{{ option.optionKey }}</span>
              <span>{{ option.optionText }}</span>
            </button>
          </div>

          <div v-else class="text-answer">
            <div v-if="currentQuestion.type === 5" class="essay-toolbar">
              <div class="essay-mode-group">
                <button
                  type="button"
                  :class="['essay-mode-button', currentEssayMode === 'text' ? 'active' : '']"
                  @click="switchEssayMode('text')"
                >
                  文本
                </button>
                <button
                  type="button"
                  :class="['essay-mode-button', currentEssayMode === 'canvas' ? 'active' : '']"
                  @click="switchEssayMode('canvas')"
                >
                  手写
                </button>
              </div>
              <span class="essay-upload-status" v-if="currentEssayCanvasObjectName">手写稿已保存</span>
            </div>

            <div v-if="currentQuestion.type === 5 && currentEssayMode === 'canvas'" class="essay-canvas-wrap">
              <AnswerCanvas v-model="currentEssayCanvasDraft" :height="280" />
              <p class="essay-tip">手写过程会在提交试卷前自动上传保存。</p>
              <div class="essay-canvas-actions">
                <button type="button" class="ghost-button" :disabled="!currentEssayCanvasDraft" @click="clearEssayCanvasDraft">
                  清空手写
                </button>
              </div>
            </div>
            <textarea
              :value="textAnswerValue"
              :class="currentQuestion.type === 5 && currentEssayMode === 'canvas' ? 'essay-conclusion-textarea' : ''"
              :rows="currentQuestion.type === 5 && currentEssayMode === 'canvas' ? 4 : 6"
              :placeholder="currentQuestion.type === 5 && currentEssayMode === 'canvas' ? '可选：补充文字结论，便于系统判题' : '请输入你的答案'"
              @input="setTextAnswer($event.target.value)"
            ></textarea>
          </div>

          <div class="question-actions">
            <button type="button" class="ghost-button" :disabled="currentIndex === 0" @click="goToPrevious">
              上一题
            </button>
            <button
              type="button"
              class="ghost-button"
              :disabled="currentIndex >= questions.length - 1"
              @click="goToNext"
            >
              下一题
            </button>
            <button type="button" :disabled="submitting || essayCanvasUploading || imageAnnotationUploading" @click="submitExam">
              {{ submitting ? '交卷中...' : '提交试卷' }}
            </button>
          </div>
        </section>
      </template>
    </template>
  </div>
</template>

<script setup>
import { computed, onBeforeUnmount, onMounted, ref, watch } from 'vue'
import { onBeforeRouteLeave, useRoute } from 'vue-router'
import { showToast } from 'vant'
import AnswerCanvas from '../../../components/AnswerCanvas.vue'
import QuestionImageList from '../../../components/QuestionImageList.vue'
import fileApi from '../../common/api/file'
import { buildEssayAnswerPayload, parseEssayAnswerPayload } from '../../common/utils/essayCanvasAnswer'
import {
  buildImageAnnotationPayload,
  parseImageAnnotationPayload
} from '../../common/utils/imageAnnotationAnswer'
import { parseQuestionImageRefs } from '../../common/utils/questionImages'
import examApi from '../api/exam'
import {
  buildSessionCacheKey,
  buildSessionStateKey,
  formatDateTime,
  formatScore,
  isLikelyBooleanText,
  parseQuestionOptions,
  resolveDifficultyLabel,
  resolveTypeLabel
} from '../utils/examHelpers'

const route = useRoute()

const loading = ref(true)
const submitting = ref(false)
const examSession = ref(null)
const questions = ref([])
const currentIndex = ref(0)
const answers = ref({})
const essayAnswerModes = ref({})
const essayCanvasDrafts = ref({})
const essayCanvasObjectNames = ref({})
const essayCanvasUploading = ref(false)
const essayCanvasLoading = ref({})
const imageAnnotationDrafts = ref({})
const imageAnnotationObjectNames = ref({})
const imageAnnotationUploading = ref(false)
const imageAnnotationLoading = ref({})
const answerTimeSeconds = ref({})
const enteredAt = ref(0)
const remainingSeconds = ref(0)
const submittedResult = ref(null)
const countdownTimer = ref(null)
const autoSubmitted = ref(false)

const recordId = computed(() => Number(route.params.recordId || 0))
const sessionCacheKey = computed(() => buildSessionCacheKey(recordId.value))
const stateCacheKey = computed(() => buildSessionStateKey(recordId.value))

const examDurationMinutes = computed(() => {
  const duration = Number(examSession.value?.duration || 0)
  return duration > 0 ? duration : 120
})

const totalDurationSeconds = computed(() => examDurationMinutes.value * 60)

const currentQuestion = computed(() => questions.value[currentIndex.value] || null)
const currentOptions = computed(() => parseQuestionOptions(currentQuestion.value?.options))
const questionMapById = computed(() => {
  return Object.fromEntries(
    questions.value
      .filter((question) => question?.questionId)
      .map((question) => [Number(question.questionId), question])
  )
})

const currentEssayMode = computed({
  get() {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId || Number(currentQuestion.value?.type) !== 5) {
      return 'text'
    }
    return essayAnswerModes.value[questionId] === 'canvas' ? 'canvas' : 'text'
  },
  set(mode) {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId || Number(currentQuestion.value?.type) !== 5) {
      return
    }
    essayAnswerModes.value = {
      ...essayAnswerModes.value,
      [questionId]: mode === 'canvas' ? 'canvas' : 'text'
    }
  }
})

const currentEssayCanvasDraft = computed({
  get() {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId || Number(currentQuestion.value?.type) !== 5) {
      return ''
    }
    return essayCanvasDrafts.value[questionId] || ''
  },
  set(value) {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId || Number(currentQuestion.value?.type) !== 5) {
      return
    }
    const nextDraft = value ? String(value) : ''
    essayCanvasDrafts.value = {
      ...essayCanvasDrafts.value,
      [questionId]: nextDraft
    }
    essayCanvasObjectNames.value = {
      ...essayCanvasObjectNames.value,
      [questionId]: ''
    }
  }
})

const currentEssayCanvasObjectName = computed(() => {
  const questionId = Number(currentQuestion.value?.questionId || 0)
  if (!questionId || Number(currentQuestion.value?.type) !== 5) {
    return ''
  }
  return String(essayCanvasObjectNames.value[questionId] || '').trim()
})

const currentImageAnnotationDrafts = computed({
  get() {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId) {
      return {}
    }
    return imageAnnotationDrafts.value[questionId] || {}
  },
  set(value) {
    const questionId = Number(currentQuestion.value?.questionId || 0)
    if (!questionId) {
      return
    }
    const nextDrafts = value || {}
    const previousDrafts = imageAnnotationDrafts.value[questionId] || {}
    const previousObjectNames = imageAnnotationObjectNames.value[questionId] || {}
    const nextObjectNames = { ...previousObjectNames }
    for (const [imageKey, dataUrl] of Object.entries(nextDrafts)) {
      if (String(dataUrl || '') !== String(previousDrafts[imageKey] || '')) {
        nextObjectNames[imageKey] = ''
      }
    }
    imageAnnotationDrafts.value = {
      ...imageAnnotationDrafts.value,
      [questionId]: nextDrafts
    }
    imageAnnotationObjectNames.value = {
      ...imageAnnotationObjectNames.value,
      [questionId]: nextObjectNames
    }
    saveClientState()
  }
})

const currentImageAnnotationObjectNames = computed(() => {
  const questionId = Number(currentQuestion.value?.questionId || 0)
  if (!questionId) {
    return {}
  }
  return imageAnnotationObjectNames.value[questionId] || {}
})

const blobToDataUrl = (blob) => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(String(reader.result || ''))
    reader.onerror = () => reject(new Error('手写草稿读取失败'))
    reader.readAsDataURL(blob)
  })
}

const loadEssayCanvasDraftFromObjectName = async (questionId, { silent = true } = {}) => {
  const normalizedQuestionId = Number(questionId || 0)
  if (!normalizedQuestionId) {
    return ''
  }
  const objectName = String(essayCanvasObjectNames.value[normalizedQuestionId] || '').trim()
  if (!objectName) {
    return ''
  }
  const draft = String(essayCanvasDrafts.value[normalizedQuestionId] || '').trim()
  if (draft) {
    return draft
  }
  if (essayCanvasLoading.value[normalizedQuestionId]) {
    return ''
  }

  essayCanvasLoading.value = {
    ...essayCanvasLoading.value,
    [normalizedQuestionId]: true
  }

  try {
    const blob = await fileApi.download(objectName)
    const dataUrl = await blobToDataUrl(blob)
    if (!dataUrl) {
      return ''
    }
    if (String(essayCanvasObjectNames.value[normalizedQuestionId] || '').trim() !== objectName) {
      return ''
    }
    essayCanvasDrafts.value = {
      ...essayCanvasDrafts.value,
      [normalizedQuestionId]: dataUrl
    }
    return dataUrl
  } catch (error) {
    if (!silent) {
      showToast(error.message || '手写草稿加载失败')
    }
    return ''
  } finally {
    essayCanvasLoading.value = {
      ...essayCanvasLoading.value,
      [normalizedQuestionId]: false
    }
  }
}

const ensureCurrentEssayCanvasDraftLoaded = async ({ silent = true } = {}) => {
  const questionId = Number(currentQuestion.value?.questionId || 0)
  if (!questionId || Number(currentQuestion.value?.type) !== 5) {
    return
  }
  if (currentEssayMode.value !== 'canvas') {
    return
  }
  await loadEssayCanvasDraftFromObjectName(questionId, { silent })
}

const loadImageAnnotationDraftsFromObjectNames = async (questionId, { silent = true } = {}) => {
  const normalizedQuestionId = Number(questionId || 0)
  if (!normalizedQuestionId) {
    return {}
  }
  const objectMap = imageAnnotationObjectNames.value[normalizedQuestionId] || {}
  const currentDrafts = imageAnnotationDrafts.value[normalizedQuestionId] || {}
  const pendingEntries = Object.entries(objectMap)
    .map(([imageKey, objectName]) => [imageKey, String(objectName || '').trim()])
    .filter(([imageKey, objectName]) => objectName && !String(currentDrafts[imageKey] || '').trim())

  if (!pendingEntries.length || imageAnnotationLoading.value[normalizedQuestionId]) {
    return currentDrafts
  }

  imageAnnotationLoading.value = {
    ...imageAnnotationLoading.value,
    [normalizedQuestionId]: true
  }

  const nextDrafts = { ...currentDrafts }
  try {
    for (const [imageKey, objectName] of pendingEntries) {
      const blob = await fileApi.download(objectName)
      const dataUrl = await blobToDataUrl(blob)
      if (dataUrl && String((imageAnnotationObjectNames.value[normalizedQuestionId] || {})[imageKey] || '').trim() === objectName) {
        nextDrafts[imageKey] = dataUrl
      }
    }
    imageAnnotationDrafts.value = {
      ...imageAnnotationDrafts.value,
      [normalizedQuestionId]: nextDrafts
    }
    saveClientState()
    return nextDrafts
  } catch (error) {
    if (!silent) {
      showToast(error.message || '图片辅助线加载失败')
    }
    return currentDrafts
  } finally {
    imageAnnotationLoading.value = {
      ...imageAnnotationLoading.value,
      [normalizedQuestionId]: false
    }
  }
}

const ensureCurrentImageAnnotationDraftsLoaded = async ({ silent = true } = {}) => {
  const questionId = Number(currentQuestion.value?.questionId || 0)
  if (!questionId) {
    return
  }
  await loadImageAnnotationDraftsFromObjectNames(questionId, { silent })
}

const answeredCount = computed(() => {
  let count = 0
  for (const question of questions.value) {
    if (isAnswered(question.questionId)) {
      count++
    }
  }
  return count
})

const displayRemainingTime = computed(() => {
  const safe = Math.max(remainingSeconds.value, 0)
  const minutes = Math.floor(safe / 60)
  const seconds = safe % 60
  return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`
})

const timeClass = computed(() => {
  if (remainingSeconds.value <= 60) {
    return 'danger-text'
  }
  if (remainingSeconds.value <= 300) {
    return 'warn-text'
  }
  return ''
})

const textAnswerValue = computed(() => {
  if (!currentQuestion.value) {
    return ''
  }
  const raw = answers.value[currentQuestion.value.questionId]
  return typeof raw === 'string' ? raw : ''
})

const loadSessionFromCache = () => {
  const raw = sessionStorage.getItem(sessionCacheKey.value)
  if (!raw) {
    return null
  }
  try {
    return JSON.parse(raw)
  } catch (error) {
    return null
  }
}

const loadClientState = () => {
  const raw = sessionStorage.getItem(stateCacheKey.value)
  if (!raw) {
    return null
  }
  try {
    return JSON.parse(raw)
  } catch (error) {
    return null
  }
}

const saveClientState = () => {
  if (!recordId.value || submittedResult.value) {
    return
  }
  const payload = {
    currentIndex: currentIndex.value,
    answers: answers.value,
    essayAnswerModes: essayAnswerModes.value,
    essayCanvasDrafts: essayCanvasDrafts.value,
    essayCanvasObjectNames: essayCanvasObjectNames.value,
    imageAnnotationDrafts: imageAnnotationDrafts.value,
    imageAnnotationObjectNames: imageAnnotationObjectNames.value,
    answerTimeSeconds: answerTimeSeconds.value
  }
  sessionStorage.setItem(stateCacheKey.value, JSON.stringify(payload))
}

const clearClientState = () => {
  sessionStorage.removeItem(sessionCacheKey.value)
  sessionStorage.removeItem(stateCacheKey.value)
}

const calcRemainingSeconds = (startTime) => {
  const startAt = new Date(startTime).getTime()
  if (!startAt || Number.isNaN(startAt)) {
    return totalDurationSeconds.value
  }
  const elapsed = Math.max(Math.floor((Date.now() - startAt) / 1000), 0)
  return Math.max(totalDurationSeconds.value - elapsed, 0)
}

const initializeSession = () => {
  const payload = loadSessionFromCache()
  if (!payload?.examRecordId || payload.examRecordId !== recordId.value) {
    loading.value = false
    examSession.value = null
    return
  }

  examSession.value = payload
  questions.value = [...(payload.questions || [])]
    .filter((item) => item && item.questionId)
    .sort((left, right) => {
      const sortLeft = Number(left.sort || 0)
      const sortRight = Number(right.sort || 0)
      if (sortLeft === sortRight) {
        return Number(left.questionId) - Number(right.questionId)
      }
      return sortLeft - sortRight
    })

  const state = loadClientState()
  if (state) {
    const stateAnswers = state.answers || {}
    const nextAnswers = {}
    const nextEssayAnswerModes = { ...(state.essayAnswerModes || {}) }
    const nextEssayCanvasObjectNames = { ...(state.essayCanvasObjectNames || {}) }
    const nextImageAnnotationObjectNames = { ...(state.imageAnnotationObjectNames || {}) }

    questions.value.forEach((question) => {
      const rawAnswer = stateAnswers[question.questionId]
      const parsedImageAnnotations = typeof rawAnswer === 'string'
        ? parseImageAnnotationPayload(rawAnswer)
        : { text: rawAnswer, annotations: [] }
      if (parsedImageAnnotations.annotations.length) {
        nextImageAnnotationObjectNames[question.questionId] = parsedImageAnnotations.annotations.reduce((result, item) => {
          result[item.imageObjectName] = item.annotationObjectName
          return result
        }, {})
      }
      if (Number(question.type) === 5) {
        const parsedEssayAnswer = parseEssayAnswerPayload(parsedImageAnnotations.text)
        nextAnswers[question.questionId] = parsedEssayAnswer.text
        if (parsedEssayAnswer.canvasObjectName && !nextEssayCanvasObjectNames[question.questionId]) {
          nextEssayCanvasObjectNames[question.questionId] = parsedEssayAnswer.canvasObjectName
        }
        if (!nextEssayAnswerModes[question.questionId]) {
          nextEssayAnswerModes[question.questionId] = parsedEssayAnswer.canvasObjectName && !parsedEssayAnswer.text
            ? 'canvas'
            : 'text'
        }
      } else {
        nextAnswers[question.questionId] = parsedImageAnnotations.text
      }
    })

    answers.value = nextAnswers
    essayAnswerModes.value = nextEssayAnswerModes
    essayCanvasObjectNames.value = nextEssayCanvasObjectNames
    essayCanvasDrafts.value = state.essayCanvasDrafts || {}
    imageAnnotationObjectNames.value = nextImageAnnotationObjectNames
    imageAnnotationDrafts.value = state.imageAnnotationDrafts || {}
    answerTimeSeconds.value = state.answerTimeSeconds || {}
    currentIndex.value = Math.min(
      Math.max(Number(state.currentIndex || 0), 0),
      Math.max(questions.value.length - 1, 0)
    )
  }

  remainingSeconds.value = calcRemainingSeconds(payload.startTime)
  loading.value = false
  beginCurrentQuestionTiming()
}

const clearTimer = () => {
  if (countdownTimer.value) {
    clearInterval(countdownTimer.value)
    countdownTimer.value = null
  }
}

const syncCurrentQuestionTime = () => {
  if (!currentQuestion.value || !enteredAt.value) {
    return
  }
  const delta = Math.max(Math.round((Date.now() - enteredAt.value) / 1000), 0)
  if (delta <= 0) {
    return
  }
  const questionId = currentQuestion.value.questionId
  const current = Number(answerTimeSeconds.value[questionId] || 0)
  answerTimeSeconds.value = {
    ...answerTimeSeconds.value,
    [questionId]: current + delta
  }
  enteredAt.value = Date.now()
}

const beginCurrentQuestionTiming = () => {
  enteredAt.value = Date.now()
}

const startTimer = () => {
  clearTimer()
  countdownTimer.value = setInterval(() => {
    if (remainingSeconds.value <= 0) {
      clearTimer()
      if (!submitting.value && !submittedResult.value && !autoSubmitted.value) {
        autoSubmitted.value = true
        showToast('考试时间已到，正在自动交卷')
        submitExam()
      }
      return
    }

    remainingSeconds.value -= 1
  }, 1000)
}

const isChoiceQuestion = (type) => type === 1 || type === 2 || type === 3

const isAnswered = (questionId) => {
  const value = answers.value[questionId]
  const question = questionMapById.value[Number(questionId)]
  if (Number(question?.type) === 5) {
    const textAnswered = typeof value === 'string' ? value.trim() !== '' : false
    const canvasDraft = String(essayCanvasDrafts.value[questionId] || '').trim()
    const canvasObjectName = String(essayCanvasObjectNames.value[questionId] || '').trim()
    return textAnswered || canvasDraft.length > 0 || canvasObjectName.length > 0
  }
  if (Array.isArray(value)) {
    return value.length > 0
  }
  if (typeof value === 'string') {
    return value.trim() !== ''
  }
  return false
}

const isOptionActive = (question, option) => {
  const current = answers.value[question.questionId]
  if (question.type === 2) {
    return Array.isArray(current) ? current.includes(option.optionKey) : false
  }
  return String(current || '') === option.optionKey
}

const toggleOption = (question, option) => {
  if (question.type === 2) {
    const list = Array.isArray(answers.value[question.questionId])
      ? [...answers.value[question.questionId]]
      : []
    const index = list.indexOf(option.optionKey)
    if (index >= 0) {
      list.splice(index, 1)
    } else {
      list.push(option.optionKey)
    }
    list.sort()
    answers.value = {
      ...answers.value,
      [question.questionId]: list
    }
    return
  }

  answers.value = {
    ...answers.value,
    [question.questionId]: option.optionKey
  }
}

const setTextAnswer = (value) => {
  if (!currentQuestion.value) {
    return
  }
  answers.value = {
    ...answers.value,
    [currentQuestion.value.questionId]: String(value || '')
  }
}

const switchEssayMode = (mode) => {
  currentEssayMode.value = mode
  if (mode === 'canvas') {
    void ensureCurrentEssayCanvasDraftLoaded({ silent: true })
  }
}

const clearEssayCanvasDraft = () => {
  const questionId = Number(currentQuestion.value?.questionId || 0)
  if (!questionId || Number(currentQuestion.value?.type) !== 5) {
    return
  }
  essayCanvasDrafts.value = {
    ...essayCanvasDrafts.value,
    [questionId]: ''
  }
  essayCanvasObjectNames.value = {
    ...essayCanvasObjectNames.value,
    [questionId]: ''
  }
}

const dataUrlToFile = (dataUrl, fileName) => {
  const normalized = String(dataUrl || '')
  const [header, base64] = normalized.split(',')
  if (!header || !base64) {
    return null
  }
  const mimeMatch = header.match(/data:(.*?);base64/i)
  const mimeType = mimeMatch?.[1] || 'image/png'
  const binary = window.atob(base64)
  const bytes = new Uint8Array(binary.length)
  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index)
  }
  return new File([bytes], fileName, { type: mimeType })
}

const uploadEssayCanvasForQuestion = async (questionId) => {
  const normalizedQuestionId = Number(questionId || 0)
  if (!normalizedQuestionId) {
    return ''
  }
  const existedObjectName = String(essayCanvasObjectNames.value[normalizedQuestionId] || '').trim()
  if (existedObjectName) {
    return existedObjectName
  }

  const dataUrl = String(essayCanvasDrafts.value[normalizedQuestionId] || '').trim()
  if (!dataUrl) {
    return ''
  }

  const file = dataUrlToFile(dataUrl, `exam-essay-canvas-${recordId.value}-${normalizedQuestionId}.png`)
  if (!file) {
    return ''
  }

  const response = await fileApi.upload(file)
  const objectName = String(response?.objectName || response?.data?.objectName || '').trim()
  if (!objectName) {
    throw new Error('手写稿上传失败，请稍后重试')
  }
  essayCanvasObjectNames.value = {
    ...essayCanvasObjectNames.value,
    [normalizedQuestionId]: objectName
  }
  return objectName
}

const ensureEssayCanvasUploaded = async ({ silent = true, throwOnError = false } = {}) => {
  const essayQuestionIds = questions.value
    .filter((question) => Number(question.type) === 5)
    .map((question) => Number(question.questionId))
    .filter((questionId) => {
      const draft = String(essayCanvasDrafts.value[questionId] || '').trim()
      const objectName = String(essayCanvasObjectNames.value[questionId] || '').trim()
      return draft.length > 0 && !objectName
    })

  if (!essayQuestionIds.length) {
    return
  }

  essayCanvasUploading.value = true
  try {
    for (const questionId of essayQuestionIds) {
      await uploadEssayCanvasForQuestion(questionId)
    }
  } catch (error) {
    if (!silent) {
      showToast(error.message || '手写稿上传失败')
    }
    if (throwOnError) {
      throw error
    }
  } finally {
    essayCanvasUploading.value = false
  }
}

const buildImageAnnotationUploadFileName = (questionId, imageKey) => {
  const safeKey = String(imageKey || 'image').replace(/[^a-zA-Z0-9_.-]/g, '-').slice(-80)
  return `exam-image-annotation-${recordId.value}-${questionId}-${Date.now()}-${safeKey}.png`
}

const uploadImageAnnotationsForQuestion = async (question) => {
  const questionId = Number(question?.questionId || 0)
  if (!questionId) {
    return {}
  }

  const drafts = imageAnnotationDrafts.value[questionId] || {}
  const uploaded = imageAnnotationObjectNames.value[questionId] || {}
  const nextUploaded = { ...uploaded }
  const refs = parseQuestionImageRefs(question.imageUrls)

  for (const item of refs) {
    const imageKey = item.objectName || item.key
    if (!imageKey) {
      continue
    }
    const dataUrl = String(drafts[imageKey] || '').trim()
    if (!dataUrl) {
      delete nextUploaded[imageKey]
      continue
    }
    if (String(nextUploaded[imageKey] || '').trim()) {
      continue
    }
    const file = dataUrlToFile(dataUrl, buildImageAnnotationUploadFileName(questionId, imageKey))
    if (!file) {
      continue
    }

    const response = await fileApi.upload(file)
    const objectName = String(response?.objectName || response?.data?.objectName || '').trim()
    if (!objectName) {
      throw new Error('图片辅助线保存失败，请稍后重试')
    }
    nextUploaded[imageKey] = objectName
  }

  imageAnnotationObjectNames.value = {
    ...imageAnnotationObjectNames.value,
    [questionId]: nextUploaded
  }
  saveClientState()
  return nextUploaded
}

const ensureImageAnnotationsUploaded = async ({ silent = true, throwOnError = false } = {}) => {
  const pendingQuestionIds = questions.value
    .map((question) => Number(question.questionId))
    .filter((questionId) => {
      const question = questionMapById.value[Number(questionId)]
      if (!question?.imageUrls) {
        return false
      }
      const refs = parseQuestionImageRefs(question.imageUrls)
      const drafts = imageAnnotationDrafts.value[questionId] || {}
      const uploaded = imageAnnotationObjectNames.value[questionId] || {}
      return refs.some((item) => {
        const imageKey = item.objectName || item.key
        return String(drafts[imageKey] || '').trim() && !String(uploaded[imageKey] || '').trim()
      })
    })

  if (!pendingQuestionIds.length) {
    return
  }

  imageAnnotationUploading.value = true
  try {
    for (const questionId of pendingQuestionIds) {
      await uploadImageAnnotationsForQuestion(questionMapById.value[Number(questionId)])
    }
  } catch (error) {
    if (!silent) {
      showToast(error.message || '图片辅助线保存失败')
    }
    if (throwOnError) {
      throw error
    }
  } finally {
    imageAnnotationUploading.value = false
  }
}

const goToQuestion = (index) => {
  if (index < 0 || index >= questions.value.length || index === currentIndex.value) {
    return
  }
  syncCurrentQuestionTime()
  currentIndex.value = index
  beginCurrentQuestionTiming()
}

const goToPrevious = () => {
  goToQuestion(currentIndex.value - 1)
}

const goToNext = () => {
  goToQuestion(currentIndex.value + 1)
}

const resolveJudgementAnswer = (question, optionKey) => {
  const options = parseQuestionOptions(question.options)
  const option = options.find((item) => item.optionKey === optionKey)
  if (!option) {
    return optionKey || ''
  }
  const text = String(option.optionText || '').trim()
  if (isLikelyBooleanText(text)) {
    return text
  }
  return option.optionKey || text
}

const buildQuestionImageAnnotationPayload = (question, text) => {
  const questionId = Number(question?.questionId || 0)
  const objectMap = imageAnnotationObjectNames.value[questionId] || {}
  const annotations = Object.entries(objectMap)
    .map(([imageObjectName, annotationObjectName]) => ({
      imageObjectName,
      annotationObjectName
    }))
    .filter((item) => String(item.imageObjectName || '').trim() && String(item.annotationObjectName || '').trim())
  return buildImageAnnotationPayload(text, annotations)
}

const buildUserAnswer = (question) => {
  const raw = answers.value[question.questionId]
  let answerText = ''
  if (question.type === 2) {
    answerText = Array.isArray(raw) ? raw.slice().sort().join(',') : ''
  } else if (question.type === 3) {
    answerText = resolveJudgementAnswer(question, String(raw || ''))
  } else if (question.type === 5) {
    answerText = buildEssayAnswerPayload({
      text: typeof raw === 'string' ? raw.trim() : '',
      canvasObjectName: essayCanvasObjectNames.value[question.questionId] || ''
    })
  } else if (question.type === 4) {
    answerText = typeof raw === 'string' ? raw.trim() : ''
  } else {
    answerText = typeof raw === 'string' ? raw : ''
  }
  return buildQuestionImageAnnotationPayload(question, answerText)
}

const buildAnswerTime = (questionId) => {
  const raw = Number(answerTimeSeconds.value[questionId] || 0)
  return raw > 0 ? raw : 0
}

const submitExam = async () => {
  if (!recordId.value || submitting.value || submittedResult.value || !questions.value.length) {
    return
  }

  syncCurrentQuestionTime()
  submitting.value = true

  try {
    await ensureEssayCanvasUploaded({ silent: false, throwOnError: true })
    await ensureImageAnnotationsUploaded({ silent: false, throwOnError: true })

    const usedSeconds = totalDurationSeconds.value - Math.max(remainingSeconds.value, 0)
    const payload = {
      answers: questions.value.map((question) => ({
        questionId: question.questionId,
        userAnswer: buildUserAnswer(question),
        answerTime: buildAnswerTime(question.questionId)
      })),
      duration: Math.max(Math.round(usedSeconds / 60), 0)
    }

    const response = await examApi.submit(recordId.value, payload)
    submittedResult.value = response.data
    clearTimer()
    clearClientState()
    showToast('交卷成功')
  } catch (error) {
    showToast(error.message || '交卷失败')
  } finally {
    submitting.value = false
  }
}

watch(
  answers,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  answerTimeSeconds,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  essayAnswerModes,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  essayCanvasDrafts,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  essayCanvasObjectNames,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  imageAnnotationDrafts,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(
  imageAnnotationObjectNames,
  () => {
    saveClientState()
  },
  { deep: true }
)

watch(currentIndex, () => {
  saveClientState()
})

watch(
  () => [currentQuestion.value?.questionId, currentEssayMode.value, currentEssayCanvasObjectName.value],
  ([questionId, mode, objectName]) => {
    if (!questionId || mode !== 'canvas' || !objectName) {
      return
    }
    void ensureCurrentEssayCanvasDraftLoaded({ silent: true })
  }
)

watch(
  () => [currentQuestion.value?.questionId, currentQuestion.value?.imageUrls],
  ([questionId, imageUrls]) => {
    if (!questionId || !imageUrls) {
      return
    }
    void ensureCurrentImageAnnotationDraftsLoaded({ silent: true })
  }
)

onBeforeRouteLeave((to, from, next) => {
  if (submittedResult.value || !examSession.value) {
    next()
    return
  }

  const confirmed = window.confirm('离开作答页面后将中断本次答题，确认离开吗？')
  if (!confirmed) {
    next(false)
    return
  }

  syncCurrentQuestionTime()
  saveClientState()
  next()
})

onMounted(() => {
  initializeSession()
  if (examSession.value && !submittedResult.value) {
    startTimer()
  }
  void ensureCurrentEssayCanvasDraftLoaded({ silent: true })
  void ensureCurrentImageAnnotationDraftsLoaded({ silent: true })
})

onBeforeUnmount(() => {
  syncCurrentQuestionTime()
  saveClientState()
  clearTimer()
})
</script>

